#!/bin/bash

## This file has been generated by tools/setupbuilder.py

###########################################
##                setup.sh               ##
##   A dotfile installer for ArchLinux   ##
##                                       ##
##                 GGORG                 ##
##      https://gh.ggorg.tk/dotfiles     ##
##          shells/zsh/setup.sh          ##
